import 'package:flutter/material.dart';
import 'package:table_calendar/table_calendar.dart';
class CalendarPage extends StatefulWidget{const CalendarPage({super.key});@override State<CalendarPage> createState()=>_CalendarPageState();}
class _CalendarPageState extends State<CalendarPage>{DateTime selected=DateTime.now();@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('캘린더')),body:ListView(children:[TableCalendar(firstDay:DateTime(2020),lastDay:DateTime(2035),focusedDay:selected,selectedDayPredicate:(d)=>isSameDay(d,selected),onDaySelected:(s,f)=>setState(()=>selected=s),calendarStyle:CalendarStyle(selectedDecoration:BoxDecoration(color:Theme.of(context).colorScheme.primary,shape:BoxShape.circle))),const Padding(padding:EdgeInsets.all(16),child:Wrap(spacing:12,children:[Chip(label:Text('● 학교',style:TextStyle(color:Colors.blue))),Chip(label:Text('● 개인',style:TextStyle(color:Colors.green))),Chip(label:Text('● 시험',style:TextStyle(color:Colors.red))),Chip(label:Text('● 과제',style:TextStyle(color:Colors.amber))),Chip(label:Text('● 행사',style:TextStyle(color:Colors.purple)))]) ]),floatingActionButton:FloatingActionButton(onPressed:(){},child:const Icon(Icons.add)));}

